struct flock {
    short l_type;    // lock type: F_RDLCK, F_WRLCK, F_UNLCK
    short l_whence;  // reference position for l_start
    long  l_start;   // offset relative to l_whence
    long  l_len;     // length of locked portion in bytes
    long  l_pid;     // PID of locking process (F_GETLK only)
};

int fcntl(int df, int cmd, struct flock* p_flock);

// df      = file descriptor of the open file
// p_flock = pointer to the flock structure
// cmd     = locking mode (F_SETLK, F_SETLKW, F_GETLK)
// returns 0 on success, -1 on error

